   107→### 2. Fix TraceEmitter.ts
   108→**File**: `.claude/hooks/lib/TraceEmitter.ts` ⚠️ **CRITICAL**
   109→
   110→**Issues**:
   111→- May spawn processes for trace collection
   112→- Network operations for observability backend
   113→- File writing for trace logs
   114→- May use Unix-specific process monitoring
   115→
   116→**Solution:**
   117→```typescript
   118→import * as fs from 'fs';
   119→import * as path from 'path';
   120→import { EventEmitter } from 'events';
   121→import { PLATFORM, paths } from './paths';
   122→
   123→interface TraceEvent {
   124→  timestamp: Date;
   125→  type: string;
   126→  data: any;
   127→}
   128→
   129→export class TraceEmitter extends EventEmitter {
   130→  private traceFile: string;
   131→  private traceBuffer: TraceEvent[] = [];
   132→
   133→  constructor() {
   134→    super();
   135→    // Use cross-platform path
   136→    this.traceFile = path.join(paths.TEMP_DIR, 'trace.log');
   137→
   138→    // Ensure directory exists (cross-platform)
   139→    if (!fs.existsSync(path.dirname(this.traceFile))) {
   140→      fs.mkdirSync(path.dirname(this.traceFile), { recursive: true });
   141→    }
   142→  }
   143→
   144→  emitTrace(event: TraceEvent): void {
   145→    this.traceBuffer.push(event);
   146→
   147→    // Flush buffer periodically
   148→    if (this.traceBuffer.length >= 100) {
   149→      this.flush();
   150→    }
   151→  }
   152→
   153→  flush(): void {
   154→    if (this.traceBuffer.length === 0) return;
   155→
   156→    try {
   157→      // Append to trace file
   158→      const content = this.traceBuffer
   159→        .map(e => JSON.stringify(e))
   160→        .join('\n') + '\n';
   161→
   162→      fs.appendFileSync(this.traceFile, content, 'utf8');
   163→      this.traceBuffer = [];
   164→    } catch (error) {
   165→      console.error('Failed to write trace:', error);
   166→    }
   167→  }
   168→
   169→  // Cross-platform process monitoring
   170→  monitorProcess(pid: number): void {
   171→    if (PLATFORM === 'win32') {
   172→      // Windows: use tasklist or PowerShell
   173→      const { spawn } = require('child_process');
   174→      spawn('tasklist', ['/FI', `PID eq ${pid}`]);
   175→    } else {
   176→      // Unix: use ps
   177→      const { spawn } = require('child_process');
   178→      spawn('ps', ['-p', pid.toString()]);
   179→    }
   180→  }
   181→}
   182→```
