     1→#!/usr/bin/env bun
     2→/**
     3→ * ISCValidator.ts - ISC File Validation Handler (Stop Event)
     4→ *
     5→ * PURPOSE:
     6→ * Validates that ISC.json was properly populated during algorithm execution.
     7→ * Checks for empty criteria arrays and stale THREAD.md phases.
     8→ *
     9→ * VALIDATION RULES:
    10→ * 1. ISC.json criteria array must be non-empty after OBSERVE
    11→ * 2. ISC.json must have been modified since session start
    12→ * 3. THREAD.md should not have _Pending..._ placeholders
    13→ *
    14→ * BEHAVIOR:
    15→ * - Currently WARNS (logs to stderr) if validation fails
    16→ * - TODO: Can be upgraded to BLOCK response if validation fails
    17→ *
    18→ * CALLED BY: StopOrchestrator.hook.ts
    19→ */
    20→
    21→import { existsSync, readFileSync, statSync } from 'fs';
    22→import { join } from 'path';
    23→import { getPaiDir } from '../lib/paths';
    24→import type { ParsedTranscript } from '../../skills/PAI/Tools/TranscriptParser';
    25→
    26→interface CurrentWork {
    27→  session_id: string;
    28→  session_dir: string;
    29→  current_task: string;
    30→  task_count: number;
    31→  created_at: string;
    32→}
    33→
    34→interface ISCData {
    35→  taskId: string;
    36→  status: string;
    37→  effortLevel: string;
    38→  criteria: string[];
    39→  antiCriteria: string[];
    40→  satisfaction: Record<string, boolean> | null;
    41→  createdAt: string;
    42→  updatedAt: string;
    43→}
    44→
    45→interface ValidationResult {
    46→  valid: boolean;
    47→  warnings: string[];
    48→  errors: string[];
    49→}
    50→
    51→const BASE_DIR = getPaiDir();
    52→const WORK_DIR = join(BASE_DIR, 'MEMORY', 'WORK');
    53→const STATE_DIR = join(BASE_DIR, 'MEMORY', 'STATE');
    54→const CURRENT_WORK_FILE = join(STATE_DIR, 'current-work.json');
    55→
    56→function readCurrentWork(): CurrentWork | null {
    57→  try {
    58→    if (!existsSync(CURRENT_WORK_FILE)) return null;
    59→    return JSON.parse(readFileSync(CURRENT_WORK_FILE, 'utf-8'));
    60→  } catch {
    61→    return null;
    62→  }
    63→}
    64→
    65→function readISC(taskPath: string): ISCData | null {
    66→  try {
    67→    const iscPath = join(taskPath, 'ISC.json');
    68→    if (!existsSync(iscPath)) return null;
    69→    return JSON.parse(readFileSync(iscPath, 'utf-8'));
    70→  } catch {
    71→    return null;
    72→  }
    73→}
    74→
    75→function readThread(taskPath: string): string | null {
    76→  try {
    77→    const threadPath = join(taskPath, 'THREAD.md');
    78→    if (!existsSync(threadPath)) return null;
    79→    return readFileSync(threadPath, 'utf-8');
    80→  } catch {
    81→    return null;
    82→  }
    83→}
    84→
    85→function getFileModTime(filePath: string): Date | null {
    86→  try {
    87→    if (!existsSync(filePath)) return null;
    88→    const stats = statSync(filePath);
    89→    return stats.mtime;
    90→  } catch {
    91→    return null;
    92→  }
    93→}
    94→
    95→function validate(taskPath: string, currentWork: CurrentWork): ValidationResult {
    96→  const result: ValidationResult = {
    97→    valid: true,
    98→    warnings: [],
    99→    errors: [],
   100→  };
   101→
   102→  // Check ISC.json
   103→  const isc = readISC(taskPath);
   104→  if (!isc) {
   105→    result.errors.push('ISC.json not found or unreadable');
   106→    result.valid = false;
   107→    return result;
   108→  }
   109→
   110→  // Rule 1: Criteria array must be non-empty
   111→  if (!isc.criteria || isc.criteria.length === 0) {
   112→    result.warnings.push('ISC.json criteria array is EMPTY - algorithm may not have executed properly');
   113→  }
   114→
   115→  // Rule 2: Check if ISC.json was modified after session start
   116→  const iscPath = join(taskPath, 'ISC.json');
   117→  const iscModTime = getFileModTime(iscPath);
   118→  const sessionStart = new Date(currentWork.created_at);
   119→
   120→  if (iscModTime && iscModTime <= sessionStart) {
   121→    result.warnings.push('ISC.json not modified since session start - no updates during algorithm execution');
   122→  }
   123→
   124→  // Check THREAD.md
   125→  const thread = readThread(taskPath);
   126→  if (!thread) {
   127→    result.errors.push('THREAD.md not found or unreadable');
   128→    result.valid = false;
   129→    return result;
   130→  }
   131→
   132→  // Rule 3: Check for _Pending..._ placeholders
   133→  const pendingCount = (thread.match(/_Pending\.\.\._/g) || []).length;
   134→  if (pendingCount > 0) {
   135→    result.warnings.push(`THREAD.md has ${pendingCount} phases still marked _Pending..._ - algorithm phases not logged`);
   136→  }
   137→
   138→  return result;
   139→}
   140→
   141→export interface ISCValidationResult {
   142→  shouldBlock: boolean;
   143→  blockReason?: string;
   144→  warnings: string[];
   145→  errors: string[];
   146→}
   147→
   148→export async function handleISCValidation(
   149→  parsed: ParsedTranscript,
   150→  hookInput: { session_id: string }
   151→): Promise<ISCValidationResult> {
   152→  const result: ISCValidationResult = {
   153→    shouldBlock: false,
   154→    warnings: [],
   155→    errors: [],
   156→  };
   157→
   158→  const currentWork = readCurrentWork();
   159→  if (!currentWork) {
   160→    console.error('[ISCValidator] No current work found - skipping validation');
   161→    return result;
   162→  }
   163→
   164→  // Skip if session IDs don't match
   165→  if (currentWork.session_id !== hookInput.session_id) {
